SELECT image.mgr_seq, image.reg_id, image.reg_dat, image.img_desc, image.img_nm, image.img_path

FROM xeus.crms_image_rqst rqst
LEFT JOIN xeus.crms_image_join imgjoin ON rqst.mgr_seq = imgjoin.rqst_mgr_seq
LEFT JOIN xeus.crms_image image ON imgjoin.img_mgr_seq = image.mgr_seq


    image.mgr_seq = imgjoin.img_mgr_seq


        AND imgjoin.rqst_mgr_seq = #{rqstMgrSeq}::numeric



        AND image.mgr_seq = #{mgrSeq}::numeric



        AND image.reg_id LIKE '%'||#{regId}||'%'



        AND image.reg_dat = #{regDat}



        AND image.img_desc = #{imgDesc}



        AND image.img_nm = #{imgNm}



        AND image.img_path = #{imgPath}






        ${sortCol} ${sortTyp}


        image.mgr_seq ASC

