			#{mgrSeq}::numeric, #{reqstId}, #{reqstDat}, #{reqstDetail}, #{docNo}, #{docFileNm}, #{docFilePath}, #{procStatCd}, #{acptUserId}, #{acptDat}, #{rejtResn}
		);

